--------------------------------------------------------------------------
-- THE HUB - DBA Team Planning Dashboard
-- Schema + seed data generated from DBA_Team_Planning_Workbook_V42
-- Target: Oracle Autonomous Database (Free Container Image) / APEX
-- Run as schema THEHUB (APEX-enabled application schema)
--------------------------------------------------------------------------

SET DEFINE OFF

--==========================================================================
-- 1. LOOKUP / REFERENCE TABLES  (mirrors 'LISTS - EDIT ME')
--==========================================================================

CREATE TABLE statuses (
  status_name  VARCHAR2(50) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE priorities (
  priority_name  VARCHAR2(50) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE workstreams (
  workstream_name  VARCHAR2(100) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE categories (
  category_name  VARCHAR2(100) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE goals (
  goal_name  VARCHAR2(150) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE meeting_statuses (
  status_name  VARCHAR2(50) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE meeting_types (
  type_name  VARCHAR2(100) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE cadences (
  cadence_name  VARCHAR2(50) PRIMARY KEY,
  sort_order NUMBER
);

CREATE TABLE report_timeframes (
  timeframe_name  VARCHAR2(50) PRIMARY KEY,
  sort_order NUMBER
);

-- seed: statuses

