--==========================================================================
-- 2. TEAM MEMBERS
--==========================================================================

CREATE TABLE team_members (
  member_id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  full_name    VARCHAR2(100) NOT NULL UNIQUE,
  role         VARCHAR2(100),
  active_flag  VARCHAR2(1) DEFAULT 'Y' CHECK (active_flag IN ('Y','N'))
);


--==========================================================================
-- 3. PROJECTS
--==========================================================================

CREATE TABLE projects (
  project_id    VARCHAR2(20) PRIMARY KEY,
  workstream    VARCHAR2(100),
  initiative    VARCHAR2(200) NOT NULL,
  category      VARCHAR2(100),
  owner         VARCHAR2(100),
  start_date    DATE,
  finish_date   DATE,
  status        VARCHAR2(50),
  priority      VARCHAR2(50),
  goal          VARCHAR2(150),
  go_live_flag  VARCHAR2(3) CHECK (go_live_flag IN ('Yes','No'))
);


--==========================================================================
-- 4. MILESTONES  (project_id is free text -- includes pseudo-buckets like
--    'ORA-MRP' / 'ORA-SEC' used for patch-cycle grouping, not strict FK)
--==========================================================================

CREATE TABLE milestones (
  milestone_id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  project_id      VARCHAR2(20),
  milestone_name  VARCHAR2(200) NOT NULL,
  milestone_date  DATE,
  category        VARCHAR2(100),
  milestone_type  VARCHAR2(100),
  owner           VARCHAR2(100),
  priority        VARCHAR2(50),
  notes           VARCHAR2(2000)
);


--==========================================================================
-- 5. LEAVE ENTRIES
--==========================================================================

CREATE TABLE leave (
  leave_id    NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  member_id   NUMBER NOT NULL REFERENCES team_members(member_id),
  leave_date  DATE NOT NULL,
  hours       NUMBER(5,2) NOT NULL,
  time_type   VARCHAR2(50),
  status      VARCHAR2(50),
  notes       VARCHAR2(500)
);


--==========================================================================
-- 6. ON-CALL ASSIGNMENTS
--==========================================================================

CREATE TABLE on_call (
  on_call_id        NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  week_start         DATE NOT NULL,
  week_end            DATE NOT NULL,
  primary_member_id  NUMBER REFERENCES team_members(member_id),
  pattern_source      VARCHAR2(200),
  conflict_flag       VARCHAR2(3) CHECK (conflict_flag IN ('Yes','No')),
  conflict_details    VARCHAR2(500)
);


--==========================================================================
-- 7. MEETINGS
--==========================================================================

CREATE TABLE meetings (
  meeting_id         NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  meeting_name       VARCHAR2(200) NOT NULL,
  meeting_date       DATE NOT NULL,
  start_time         VARCHAR2(20),
  workspace_project  VARCHAR2(200),
  audience_owner     VARCHAR2(150),
  cadence            VARCHAR2(50),
  meeting_type       VARCHAR2(100),
  purpose_notes      VARCHAR2(1000),
  status             VARCHAR2(50),
  include_flag       VARCHAR2(3) CHECK (include_flag IN ('Yes','No')),
  report_rank        NUMBER,
  dashboard_rank     NUMBER
);


--==========================================================================
-- 8. HOLIDAYS
--==========================================================================

CREATE TABLE holidays (
  holiday_date   DATE PRIMARY KEY,
  holiday_name   VARCHAR2(150) NOT NULL,
  holiday_year   NUMBER,
  included_flag  VARCHAR2(20)
);

CREATE TABLE holiday_notes (
  note_key   VARCHAR2(100) PRIMARY KEY,
  note_text  VARCHAR2(1000) NOT NULL
);



--==========================================================================
-- 9. ORACLE RU CALENDAR
--==========================================================================

CREATE TABLE oracle_ru_calendar (
  ru                     VARCHAR2(20) PRIMARY KEY,
  cpu_ru_release_date    DATE,
  golden_image_date      DATE,
  cspu_reference         VARCHAR2(50),
  cspu_date              DATE,
  latest_mrp             VARCHAR2(50),
  mrp_date               DATE,
  dust_start             DATE,
  dust_end               DATE,
  prod_start             DATE,
  prod_end               DATE,
  stabilization_end      DATE,
  golden_image_guidance  VARCHAR2(2000)
);


--==========================================================================
-- 10. ORACLE SECURITY PATCHES
--==========================================================================

CREATE TABLE oracle_security_patches (
  patch_id        NUMBER GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  release_month   VARCHAR2(20),
  release_date    DATE,
  patch_code      VARCHAR2(20),
  release_type    VARCHAR2(100),
  planning_use    VARCHAR2(200),
  guidance        VARCHAR2(2000),
  applicability   VARCHAR2(2000),
  source_note     VARCHAR2(500)
);


--==========================================================================
-- 11. RISK REGISTER
--==========================================================================

CREATE TABLE risk_register (
  risk_id       VARCHAR2(20) PRIMARY KEY,
  project_id    VARCHAR2(20),
  risk          VARCHAR2(500),
  probability   VARCHAR2(20),
  impact        VARCHAR2(20),
  mitigation    VARCHAR2(1000)
);


--==========================================================================
-- 12. DEPENDENCIES
--==========================================================================

CREATE TABLE dependencies (
  dependency_id  VARCHAR2(20) PRIMARY KEY,
  predecessor    VARCHAR2(200),
  successor      VARCHAR2(200),
  notes          VARCHAR2(1000)
);


--==========================================================================
-- 13. CONVENIENCE VIEWS  (replace the workbook's hand-built CALC tabs)
--==========================================================================

-- Headline dashboard counts (no period filter -- whole-program totals;
-- in APEX, build the period-scoped versions as report SQL bound to
-- :P1_PERIOD_START / :P1_PERIOD_END page items instead of fixed views)
CREATE OR REPLACE VIEW v_dashboard_kpis AS
SELECT
  (SELECT COUNT(*) FROM projects)                                AS total_projects,
  (SELECT COUNT(*) FROM projects WHERE status = 'Active')        AS active_projects,
  (SELECT COUNT(*) FROM projects WHERE priority = 'High')         AS high_priority_projects,
  (SELECT COUNT(*) FROM projects WHERE go_live_flag = 'Yes')      AS go_live_projects,
  (SELECT COUNT(*) FROM on_call WHERE conflict_flag = 'Yes') AS on_call_conflict_weeks
FROM dual;

-- Leave hours by team member (Leave Summary tab equivalent)
CREATE OR REPLACE VIEW v_leave_summary AS
SELECT tm.full_name,
       le.time_type,
       COUNT(*)            AS entry_count,
       SUM(le.hours)        AS total_hours
FROM   leave le
JOIN   team_members tm ON tm.member_id = le.member_id
GROUP BY tm.full_name, le.time_type;

-- Days with 2+ team members out (Coverage Risk Dates KPI)
CREATE OR REPLACE VIEW v_coverage_risk_dates AS
SELECT leave_date, COUNT(DISTINCT member_id) AS members_out
FROM   leave
WHERE  status = 'Approved'
GROUP BY leave_date
HAVING COUNT(DISTINCT member_id) >= 2;

-- Projects grouped by DBA goal (Goal Traceability tab equivalent)
CREATE OR REPLACE VIEW v_goal_traceability AS
SELECT goal, COUNT(*) AS project_count, LISTAGG(initiative, '; ') WITHIN GROUP (ORDER BY initiative) AS projects
FROM   projects
GROUP BY goal;
