INSERT INTO oracle_ru_calendar VALUES ('19.32', DATE '2026-07-21', DATE '2026-09-01', 'August 2026', DATE '2026-08-18', 'August 2026 MRP', DATE '2026-08-18', DATE '2026-09-02', DATE '2026-09-21', DATE '2026-09-24', DATE '2026-10-12', DATE '2026-10-22', 'For UR production Oracle database server environments on Linux, build the Golden Image from the quarterly CPU/RU and include the latest applicable MRP available before image creation. MRP is the Linux production path because it contains the CSPU security content plus recommended fixes. CSPUs are tracked separately for other/non-Linux platforms, including the Oracle Windows research/testing/training server, as applicable.');
